const data = $.steps.scrapePage.response.data || $.steps.scrapePage.response || {};
const markdown = data.markdown || '';
const metadata = data.metadata || {};
return { markdown: markdown.slice(0, 25000), title: metadata.title || '', description: metadata.description || '', charCount: markdown.length, url: $.input.url };

const d = $.steps.prepareContent.output;
const focus = $.input.extractionFocus || 'Extract all key information';

let prompt = 'You are a web content extraction specialist. Analyze the following webpage content and extract structured information.\n\n';
prompt += 'URL: ' + d.url + '\n';
prompt += 'PAGE TITLE: ' + d.title + '\n';
prompt += 'CONTENT LENGTH: ' + d.charCount + ' characters\n';
prompt += 'EXTRACTION FOCUS: ' + focus + '\n\n';
prompt += 'PAGE CONTENT:\n' + d.markdown + '\n\n';
prompt += 'INSTRUCTIONS:\n';
prompt += '- Extract and organize the key content into structured categories\n';
prompt += '- Identify main headings and their content\n';
prompt += '- Extract any data tables, lists, or structured data\n';
prompt += '- Find contact information, links, dates, prices if present\n';
prompt += '- Summarize the page purpose and main message\n\n';
prompt += 'Return ONLY valid JSON:\n';
prompt += '{\n';
prompt += '  "pageTitle": "title",\n';
prompt += '  "pageType": "blog|product|landing|documentation|news|other",\n';
prompt += '  "summary": "2-3 sentence summary of the page",\n';
prompt += '  "mainSections": [{ "heading": "section heading", "content": "key content from this section" }],\n';
prompt += '  "extractedData": [{ "category": "prices|contacts|dates|links|other", "items": ["item1"] }],\n';
prompt += '  "keyFacts": ["important fact 1", "important fact 2"],\n';
prompt += '  "metadata": { "author": "", "publishDate": "", "language": "", "wordCount": 0 }\n';
prompt += '}';

return { prompt };

let raw = $.steps.aiExtraction.output || '';
raw = raw.replace(/^```json\s*/i, '').replace(/^```\s*/i, '').replace(/\s*```$/i, '').trim();
try { return JSON.parse(raw); } catch(e) { return { pageTitle: '', pageType: 'other', summary: raw, mainSections: [], extractedData: [], keyFacts: [], metadata: {} }; }

const ai = $.steps.parseAI.output;
const today = new Date().toISOString().slice(0, 10);
const rows = [];
rows.push(['Date', 'URL', 'Page Title', 'Page Type', 'Section', 'Content', 'Key Facts']);

const factsStr = (ai.keyFacts || []).join('; ');
(ai.mainSections || []).forEach(s => {
  rows.push([today, $.input.url, ai.pageTitle || '', ai.pageType || '', s.heading || '', (s.content || '').slice(0, 1500), '']);
});
if (rows.length === 1) {
  rows.push([today, $.input.url, ai.pageTitle || '', ai.pageType || '', 'Summary', ai.summary || '', factsStr]);
} else {
  rows[1][6] = factsStr;
}

(ai.extractedData || []).forEach(d => {
  rows.push([today, $.input.url, '', '', 'Data: ' + (d.category || ''), (d.items || []).join(', '), '']);
});

return { rows, sectionCount: (ai.mainSections || []).length };

const ai = $.steps.parseAI.output;
const d = $.steps.prepareContent.output;

const blocks = [];
blocks.push({ type: 'header', text: { type: 'plain_text', text: 'Webpage Content Extracted', emoji: true } });
blocks.push({ type: 'section', text: { type: 'mrkdwn', text: '*Page:* <' + d.url + '|' + (ai.pageTitle || d.title || 'View Page') + '>\n*Type:* ' + (ai.pageType || 'unknown') + ' | *Sections:* ' + (ai.mainSections || []).length } });
blocks.push({ type: 'divider' });

if (ai.summary) {
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: '*Summary:* ' + ai.summary.slice(0, 1800) } });
  blocks.push({ type: 'divider' });
}

if (ai.keyFacts && ai.keyFacts.length > 0) {
  let factText = '*Key Facts:*\n';
  ai.keyFacts.slice(0, 8).forEach((f, i) => { factText += (i + 1) + '. ' + f + '\n'; });
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: factText.slice(0, 1800) } });
}

(ai.mainSections || []).slice(0, 4).forEach(s => {
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: '*' + s.heading + '*\n' + (s.content || '').slice(0, 400) } });
});

blocks.push({ type: 'context', elements: [{ type: 'mrkdwn', text: 'Data saved to Google Sheets | Powered by Firecrawl + Claude AI' }] });
const fallback = 'Extracted: ' + (ai.pageTitle || d.url) + ' - ' + (ai.summary || '').slice(0, 100);
return { blocks, fallback };
